import { useState } from "react";
import { registerUser, loginUser, resetPassword } from "./api";

function App() {
  const [form, setForm] = useState({
    name: "",
    aadhaar: "",
    password: "",
    role: "user"
  });

  const [mode, setMode] = useState("auth"); // 'auth' or 'forgot'

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleRegister = async () => {
    const res = await registerUser(form);
    alert(res);
  };

  const handleLogin = async () => {
    const res = await loginUser({
      aadhaar: form.aadhaar,
      password: form.password
    });
    alert(JSON.stringify(res));
  };

  const handleResetPassword = async () => {
    const res = await resetPassword({
      aadhaar: form.aadhaar,
      newPassword: form.password
    });
    alert(res);
  };

  return (
    <div className="container">
      <div className="glass-card">
        <h1>Ration System</h1>

        {mode === "auth" ? (
          <>
            <input 
              name="name" 
              className="input-field" 
              placeholder="Full Name (For Register)" 
              onChange={handleChange} 
            />
            <input 
              name="aadhaar" 
              className="input-field" 
              placeholder="Aadhaar ID" 
              onChange={handleChange} 
            />
            <input 
              name="password" 
              type="password" 
              className="input-field" 
              placeholder="Password" 
              onChange={handleChange} 
            />

            <div className="button-group">
              <button className="btn btn-secondary" onClick={handleRegister}>
                Register
              </button>
              <button className="btn btn-primary" onClick={handleLogin}>
                Login
              </button>
            </div>
            
            <p 
              style={{ marginTop: '15px', fontSize: '14px', cursor: 'pointer', color: '#38bdf8' }}
              onClick={() => setMode("forgot")}
            >
              Forgot Password?
            </p>
          </>
        ) : (
          <>
            <h3 style={{ marginBottom: '20px', fontWeight: '500' }}>Reset Password</h3>
            <input 
              name="aadhaar" 
              className="input-field" 
              placeholder="Aadhaar ID" 
              onChange={handleChange} 
            />
            <input 
              name="password" 
              type="password" 
              className="input-field" 
              placeholder="New Password" 
              onChange={handleChange} 
            />

            <div className="button-group">
              <button className="btn btn-primary" style={{ width: '100%' }} onClick={handleResetPassword}>
                Update Password
              </button>
            </div>
            
            <p 
              style={{ marginTop: '15px', fontSize: '14px', cursor: 'pointer', color: '#818cf8' }}
              onClick={() => setMode("auth")}
            >
              Back to Login
            </p>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
